+    }
+
+    /// Compare with another snapshot
+    pub fn compare_to(self: *const Self, allocator: std.mem.Allocator, other: *const Snapshot) !std.ArrayList(StatisticDiff) {
+        _ = self;
+        _ = other;
+        return std.ArrayList(StatisticDiff).init(allocator);
+    }
